mapConfig.stringValue:
local item = std.extVar("INPUT_Loop_Item");
{
  "`Is_Page_Flow`": if "IsPage" in item then item["IsPage"] == true else false
}

local inputs = {
  "`CONFIG_SharePoint_Hostname`": std.extVar("`CONFIG_SharePoint_Hostname`"),
  "INPUT_Loop_Item": std.extVar("INPUT_Loop_Item")
};
local fileObject = inputs["INPUT_Loop_Item"];
local rawUrl = fileObject["Url"];
local sharepointHost = inputs["`CONFIG_SharePoint_Hostname`"];
local urlWithPort = std.strReplace(rawUrl, "https://" + sharepointHost + "/", "https://" + sharepointHost + ":443/");
{
  "`Task_2_connectorInputPayload`": {
    "Library": "Shared Documents",
    "RemoteFile": urlWithPort,
    "HasBytes": true
  }
}

local inputs = {
  "`CONFIG_GCS_Bucket`": std.extVar("`CONFIG_GCS_Bucket`"),
  "INPUT_Loop_Item": std.extVar("INPUT_Loop_Item"),
  "`Task_2_connectorOutputPayload`": std.extVar("`Task_2_connectorOutputPayload`")
};
local fileObject = inputs["INPUT_Loop_Item"];
local fileName = fileObject["Name"];
local relativePath = fileObject["RelativePath"];
local objectName = if std.objectHas(fileObject, "_filename") then fileObject["_filename"] else if std.objectHas(fileObject, "RelativePath") && std.startsWith(fileObject["RelativePath"], "files/") then std.substr(fileObject["RelativePath"], 6, std.length(fileObject["RelativePath"]) - 6) else fileName;
local isPdf = std.endsWith(fileName, ".pdf") || std.endsWith(fileName, ".PDF");
local isDocx = std.endsWith(fileName, ".docx") || std.endsWith(fileName, ".DOCX");
local isDoc = std.endsWith(fileName, ".doc") || std.endsWith(fileName, ".DOC");
local isPptx = std.endsWith(fileName, ".pptx") || std.endsWith(fileName, ".PPTX");
local isPpt = std.endsWith(fileName, ".ppt") || std.endsWith(fileName, ".PPT");
local isXlsx = std.endsWith(fileName, ".xlsx") || std.endsWith(fileName, ".XLSX");
local isXls = std.endsWith(fileName, ".xls") || std.endsWith(fileName, ".XLS");
local isTxt = std.endsWith(fileName, ".txt") || std.endsWith(fileName, ".TXT");
local isHtml = std.endsWith(fileName, ".html") || std.endsWith(fileName, ".HTML") || std.endsWith(fileName, ".htm") || std.endsWith(fileName, ".aspx");
local contentType = if isPdf then "application/pdf" else if isDocx then "application/vnd.openxmlformats-officedocument.wordprocessingml.document" else if isDoc then "application/msword" else if isPptx then "application/vnd.openxmlformats-officedocument.presentationml.presentation" else if isPpt then "application/vnd.ms-powerpoint" else if isXlsx then "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" else if isXls then "application/vnd.ms-excel" else if isTxt then "text/plain" else if isHtml then "text/html" else "application/octet-stream";
{
  "`Task_4_connectorInputPayload`": {
    "Bucket": inputs["`CONFIG_GCS_Bucket`"],
    "ContentBytes": inputs["`Task_2_connectorOutputPayload`"][0]["ContentBytes"],
    "ObjectName": objectName,
    "FolderPath": "files",
    "ContentType": contentType,
    "HasBytes": true
  }
}

local inputs = {
  "`CONFIG_GCS_Bucket`": std.extVar("`CONFIG_GCS_Bucket`"),
  "INPUT_Loop_Item": std.extVar("INPUT_Loop_Item")
};
local pageObject = inputs["INPUT_Loop_Item"];
local fileName = pageObject["Name"];
local objectName = if std.objectHas(pageObject, "_filename") then pageObject["_filename"] else if std.objectHas(pageObject, "RelativePath") && std.startsWith(pageObject["RelativePath"], "pages/") then std.substr(pageObject["RelativePath"], 6, std.length(pageObject["RelativePath"]) - 6) else fileName;
local pdfBase64 = pageObject["VirtualContent"];
{
  "`Task_7_connectorInputPayload`": {
    "Bucket": inputs["`CONFIG_GCS_Bucket`"],
    "ContentBytes": pdfBase64,
    "ObjectName": objectName,
    "FolderPath": "pages",
    "ContentType": "application/pdf",
    "HasBytes": true
  }
}
